mapper.select:
SELECT ,
       p.patient_name, cu.real_name AS charge_user_name, ru.real_name AS refund_user_name
FROM charge_record c
LEFT JOIN patient p ON c.patient_id = p.patient_id
LEFT JOIN sys_user cu ON c.charge_user_id = cu.user_id
LEFT JOIN sys_user ru ON c.refund_user_id = ru.user_id

    AND c.patient_id = #{patientId}
    AND c.charge_type = #{chargeType}
    AND c.status = #{status}
    AND c.reg_id = #{regId}

ORDER BY c.create_time DESC

mapper.update:
UPDATE charge_record
status = #{status}, pay_type = #{payType}, refund_user_id = #{refundUserId}, refund_time = #{refundTime},
WHERE charge_id = #{chargeId}
